# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.clients = {}
        self.inventories = defaultdict(dict)  # mapping player_id to inventory content

    async def handler(self, websocket, path):
        player_id = await websocket.recv()
        self.clients[player_id] = websocket

        try:
            await self.handle_player(player_id, websocket)
        finally:
            del self.clients[player_id]

    async def handle_player(self, player_id, websocket):
        async for message in websocket:
            data = json.loads(message)
            action = data.get('action')

            if action == 'trade_request':
                await self.handle_trade(player_id, data)

    async def handle_trade(self, player_id, data):
        target_id = data.get('target_id')
        item_id = data.get('item_id')
        trade_quantity = data.get('quantity', 1)

        if target_id not in self.clients:
            await self.clients[player_id].send(json.dumps({
                'action': 'trade_response',
                'success': False,
                'reason': 'Target player not online'
            }))
            return

        if item_id not in self.inventories[player_id] or self.inventories[player_id][item_id] < trade_quantity:
            await self.clients[player_id].send(json.dumps({
                'action': 'trade_response',
                'success': False,
                'reason': 'Not enough items'
            }))
            return

        if item_id in self.inventories[target_id]:
            self.inventories[target_id][item_id] += trade_quantity
        else:
            self.inventories[target_id][item_id] = trade_quantity

        self.inventories[player_id][item_id] -= trade_quantity

        if self.inventories[player_id][item_id] == 0:
            del self.inventories[player_id][item_id]

        await self.clients[player_id].send(json.dumps({
            'action': 'trade_response',
            'success': True,
            'item_id': item_id,
            'quantity': trade_quantity,
        }))

        await self.clients[target_id].send(json.dumps({
            'action': 'trade_notification',
            'from_player': player_id,
            'item_id': item_id,
            'quantity': trade_quantity,
        }))

server = GameServer()
start_server = websockets.serve(server.handler, 'localhost', 12345)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()